vms_vector* vm_vec_scale2(vms_vector* dest, fix n, fix d)
{
#ifdef USE_OX_BRIDGE
	static int ox_bridge_logged = 0;
	if (!ox_bridge_logged)
	{
		fprintf(stderr, "[OX] vm_vec_scale2 using cd_ox_vm_vec_scale2.\n");
		ox_bridge_logged = 1;
	}
	cd_ox_vm_vec_scale2(dest->x, dest->y, dest->z, n, d, &dest->x, &dest->y, &dest->z);
#else
	if (d == 0) return dest;
	dest->x = fixmuldiv(dest->x, n, d);
	dest->y = fixmuldiv(dest->y, n, d);
	dest->z = fixmuldiv(dest->z, n, d);
#endif

	return dest;
}

let vm_vec_sub ~a:(ax, ay, az) ~b:(bx, by, bz) =
  wrap_add_i32 ~a:ax ~b:(-bx), wrap_add_i32 ~a:ay ~b:(-by), wrap_add_i32 ~a:az ~b:(-bz)
;;

let vm_vec_add2 ~a:(dx, dy, dz) ~b:(sx, sy, sz) =
  wrap_add_i32 ~a:dx ~b:sx, wrap_add_i32 ~a:dy ~b:sy, wrap_add_i32 ~a:dz ~b:sz
;;

let vm_vec_sub2 ~a:(dx, dy, dz) ~b:(sx, sy, sz) =
  wrap_add_i32 ~a:dx ~b:(-sx), wrap_add_i32 ~a:dy ~b:(-sy), wrap_add_i32 ~a:dz ~b:(-sz)
;;

let vm_vec_avg ~a:(ax, ay, az) ~b:(bx, by, bz) =
  wrap_add_i32 ~a:ax ~b:bx / 2, wrap_add_i32 ~a:ay ~b:by / 2, wrap_add_i32 ~a:az ~b:bz / 2
;;

