  48→//[ISB] Credits to Parabolicus for the not horrible port
  49→int oflow_check(fix a, fix b)
  50→{
  51→	int64_t tmp = (int64_t)abs(a) * (int64_t)abs(b);
  52→	return (tmp >> 47) ? 1 : 0;
  53→}
