  55→//find the point on the specified plane where the line intersects
  56→//returns true if point found, false if line parallel to plane
  57→//new_pnt is the found point on the plane
  58→//plane_pnt & plane_norm describe the plane
  59→//p0 & p1 are the ends of the line
  60→int find_plane_line_intersection(vms_vector* new_pnt, vms_vector* plane_pnt, vms_vector* plane_norm, vms_vector* p0, vms_vector* p1, fix rad)
  61→{
  62→	vms_vector d, w, clone;
  63→	fix num, den;
  64→	int foundK;
  65→
  66→	vm_vec_sub(&d, p1, p0);
  67→	vm_vec_sub(&w, p0, plane_pnt);
  68→
  69→	num = vm_vec_dot(plane_norm, &w);
  70→	den = -vm_vec_dot(plane_norm, &d);
  71→	clone.x = d.x;
  72→	clone.y = d.y;
  73→	clone.z = d.z;
  74→
  75→	//Why does this assert hit so often
  76→	//	Assert(num > -rad);
  77→
  78→	num -= rad;			//move point out by rad
  79→
  80→	//check for various bad values
  81→
  82→	if ((den == 0) ||					//moving parallel to wall, so can't hit it
  83→		(den > 0) &&
  84→		((num > den) ||				//frac greater than one
  85→		(-num >> 15) >= den) ||	//will overflow (large negative)
  86→			(den < 0 && num < den))		//frac greater than one
  87→		return 0;
  88→
  89→	//if (num>0) {mprintf(1,"HEY! num>0 in FVI!!!"); return 0;}
  90→	//??	Assert(num>=0);
  91→	//    Assert(num >= den);
  92→
  93→		//do check for potenial overflow
  94→	{
  95→		fix k;
  96→
  97→		if (labs(num) / (f1_0 / 2) >= labs(den)) { Int3(); return 0; }
  98→		k = fixdiv(num, den);
  99→
 100→		Assert(k <= f1_0);		//should be trapped above
 101→
 102→//		Assert(k>=0);
 103→		if (oflow_check(d.x, k) || oflow_check(d.y, k) || oflow_check(d.z, k)) return 0;
 104→		//Note: it is ok for k to be greater than 1, since this might mean
 105→		//that an object with a non-zero radius that moved from p0 to p1 
 106→		//actually hit the wall on the "other side" of p0.
 107→		foundK = k;
 108→	}
 109→
 110→	vm_vec_scale2(&d, num, den);
 111→	vm_vec_add(new_pnt, p0, &d); //we should have vm_vec_scale2_add2()
 112→
 113→	return 1;
 114→
 115→}
