 117→typedef struct vec2d
 118→{
 119→	fix i, j;
 120→} vec2d;
 121→
 122→//given largest componant of normal, return i & j
 123→//if largest componant is negative, swap i & j
 124→int ij_table[3][2] = {
 125→							{2,1},          //pos x biggest
 126→							{0,2},          //pos y biggest
 127→							{1,0},          //pos z biggest
 128→};
 129→
 130→//intersection types
 131→#define IT_NONE 0       //doesn't touch face at all
 132→#define IT_FACE 1       //touches face
 133→#define IT_EDGE 2       //touches edge of face
 134→#define IT_POINT        3       //touches vertex
 135→
 136→//see if a point in inside a face by projecting into 2d
 137→uint32_t check_point_to_face(vms_vector * checkp, segment * sp, side * s, int facenum, int nv, int* vertex_list)
 138→{
 139→	vms_vector_array checkp_array;
 140→	vms_vector_array norm;
 141→	vms_vector t;
 142→	int biggest;
 143→	///
 144→	int i, j, edge;
 145→	uint32_t edgemask;
 146→	fix check_i, check_j;
 147→	vms_vector_array v0, v1;
 148→
 149→	//memcpy(&norm, &s->normals[facenum], sizeof(vms_vector_array));
 150→	norm.xyz[0] = s->normals[facenum].x; norm.xyz[1] = s->normals[facenum].y; norm.xyz[2] = s->normals[facenum].z;
 151→	//checkp_array = (vms_vector_array*)checkp;
 152→	checkp_array.xyz[0] = checkp->x; checkp_array.xyz[1] = checkp->y; checkp_array.xyz[2] = checkp->z;
 153→
 154→	//now do 2d check to see if point is in side
 155→
 156→	//project polygon onto plane by finding largest component of normal
 157→	t.x = labs(norm.xyz[0]); t.y = labs(norm.xyz[1]); t.z = labs(norm.xyz[2]);
 158→
 159→	if (t.x > t.y) if (t.x > t.z) biggest = 0; else biggest = 2;
 160→	else if (t.y > t.z) biggest = 1; else biggest = 2;
 161→
 162→	if (norm.xyz[biggest] > 0) 
 163→	{
 164→		i = ij_table[biggest][0];
 165→		j = ij_table[biggest][1];
 166→	}
 167→	else 
 168→	{
 169→		i = ij_table[biggest][1];
 170→		j = ij_table[biggest][0];
 171→	}
 172→
 173→	//now do the 2d problem in the i,j plane
 174→
 175→	check_i = checkp_array.xyz[i];
 176→	check_j = checkp_array.xyz[j];
 177→
 178→	for (edge = edgemask = 0; edge < nv; edge++) 
 179→	{
 180→		vec2d edgevec, checkvec;
 181→		fix d;
 182→		vms_vector* lv;
 183→
 184→		lv = &Vertices[vertex_list[facenum * 3 + edge]];
 185→		v0.xyz[0] = lv->x; v0.xyz[1] = lv->y; v0.xyz[2] = lv->z;
 186→		lv = &Vertices[vertex_list[facenum * 3 + ((edge + 1) % nv)]];
 187→		v1.xyz[0] = lv->x; v1.xyz[1] = lv->y; v1.xyz[2] = lv->z;
 188→		//v0 = (vms_vector_array*)& Vertices[vertex_list[facenum * 3 + edge]];
 189→		//v1 = (vms_vector_array*)& Vertices[vertex_list[facenum * 3 + ((edge + 1) % nv)]];
 190→
 191→		edgevec.i = v1.xyz[i] - v0.xyz[i];
 192→		edgevec.j = v1.xyz[j] - v0.xyz[j];
 193→
 194→		checkvec.i = check_i - v0.xyz[i];
 195→		checkvec.j = check_j - v0.xyz[j];
 196→
 197→		d = fixmul(checkvec.i, edgevec.j) - fixmul(checkvec.j, edgevec.i);
 198→
 199→		if (d < 0)              		//we are outside of triangle
 200→			edgemask |= (1 << edge);
 201→	}
 202→
 203→	return edgemask;
 204→}
