 207→//check if a sphere intersects a face
 208→int check_sphere_to_face(vms_vector* pnt, segment* sp, side* s, int facenum, int nv, fix rad, int* vertex_list)
 209→{
 210→	vms_vector checkp = *pnt;
 211→	uint32_t edgemask;
 212→
 213→	//now do 2d check to see if point is in side
 214→
 215→	edgemask = check_point_to_face(pnt, sp, s, facenum, nv, vertex_list);
 216→
 217→	//we've gone through all the sides, are we inside?
 218→
 219→	if (edgemask == 0)
 220→		return IT_FACE;
 221→	else 
 222→	{
 223→		vms_vector edgevec, checkvec;            //this time, real 3d vectors
 224→		vms_vector closest_point;
 225→		fix edgelen, d, dist;
 226→		vms_vector* v0, * v1;
 227→		int itype;
 228→		int edgenum;
 229→
 230→		//get verts for edge we're behind
 231→
 232→		for (edgenum = 0; !(edgemask & 1); (edgemask >>= 1), edgenum++);
 233→
 234→		v0 = &Vertices[vertex_list[facenum * 3 + edgenum]];
 235→		v1 = &Vertices[vertex_list[facenum * 3 + ((edgenum + 1) % nv)]];
 236→
 237→		//check if we are touching an edge or point
 238→
 239→		vm_vec_sub(&checkvec, &checkp, v0);
 240→		edgelen = vm_vec_normalized_dir(&edgevec, v1, v0);
 241→
 242→		//find point dist from planes of ends of edge
 243→
 244→		d = vm_vec_dot(&edgevec, &checkvec);
 245→
 246→		if (d + rad < 0) return IT_NONE;                  //too far behind start point
 247→
 248→		if (d - rad > edgelen) return IT_NONE;    //too far part end point
 249→
 250→		//find closest point on edge to check point
 251→
 252→		itype = IT_POINT;
 253→
 254→		if (d < 0) closest_point = *v0;
 255→		else if (d > edgelen) closest_point = *v1;
 256→		else
 257→		{
 258→			itype = IT_EDGE;
 259→
 260→			//vm_vec_scale(&edgevec,d);
 261→			//vm_vec_add(&closest_point,v0,&edgevec);
 262→
 263→			vm_vec_scale_add(&closest_point, v0, &edgevec, d);
 264→		}
 265→
 266→		dist = vm_vec_dist(&checkp, &closest_point);
 267→
 268→		if (dist <= rad)
 269→			return (itype == IT_POINT) ? IT_NONE : itype;
 270→		else
 271→			return IT_NONE;
 272→	}
 273→
 274→
 275→}
