 277→//returns true if line intersects with face. fills in newp with intersection
 278→//point on plane, whether or not line intersects side
 279→//facenum determines which of four possible faces we have
 280→//note: the seg parm is temporary, until the face itself has a point field
 281→int check_line_to_face(vms_vector* newp, vms_vector* p0, vms_vector* p1, segment* seg, int side, int facenum, int nv, fix rad)
 282→{
 283→	{
 284→	vms_vector checkp;
 285→	int pli;
 286→	struct side* s = &seg->sides[side];
 287→	int vertex_list[6];
 288→	int num_faces;
 289→	int vertnum;
 290→	vms_vector norm;
 291→
 292→	norm = seg->sides[side].normals[facenum];
 293→
 294→	create_abs_vertex_lists(&num_faces, vertex_list, seg - Segments, side);
 295→
 296→	//use lowest point number
 297→	if (num_faces == 2)
 298→	{
 299→		vertnum = std::min(vertex_list[0], vertex_list[2]);
 300→	}
 301→	else
 302→	{
 303→		int i;
 304→		vertnum = vertex_list[0];
 305→		for (i = 1; i < 4; i++)
 306→			if (vertex_list[i] < vertnum)
 307→				vertnum = vertex_list[i];
 308→	}
 309→
 310→	int oldnewpz = newp->z;
 311→	pli = find_plane_line_intersection(newp, &Vertices[vertnum], &norm, p0, p1, rad);
 312→
 313→	if (!pli) return IT_NONE;
 314→
 315→	checkp = *newp;
 316→
 317→	//if rad != 0, project the point down onto the plane of the polygon
 318→
 319→	if (rad != 0)
 320→		vm_vec_scale_add2(&checkp, &norm, -rad);
 321→
 322→	return check_sphere_to_face(&checkp, seg, s, facenum, nv, rad, vertex_list);
 323→	}
 324→}
