 326→//returns the value of a determinant
 327→fix calc_det_value(vms_matrix* det)
 328→{
 329→	return 	fixmul(det->rvec.x, fixmul(det->uvec.y, det->fvec.z)) -
 330→		fixmul(det->rvec.x, fixmul(det->uvec.z, det->fvec.y)) -
 331→		fixmul(det->rvec.y, fixmul(det->uvec.x, det->fvec.z)) +
 332→		fixmul(det->rvec.y, fixmul(det->uvec.z, det->fvec.x)) +
 333→		fixmul(det->rvec.z, fixmul(det->uvec.x, det->fvec.y)) -
 334→		fixmul(det->rvec.z, fixmul(det->uvec.y, det->fvec.x));
 335→}
