 337→//computes the parameters of closest approach of two lines 
 338→//fill in two parameters, t0 & t1.  returns 0 if lines are parallel, else 1
 339→int check_line_to_line(fix* t1, fix* t2, vms_vector* p1, vms_vector* v1, vms_vector* p2, vms_vector* v2)
 340→{
 341→	vms_matrix det;
 342→	fix d, cross_mag2;		//mag squared cross product
 343→
 344→	vm_vec_sub(&det.rvec, p2, p1);
 345→	vm_vec_cross(&det.fvec, v1, v2);
 346→	cross_mag2 = vm_vec_dot(&det.fvec, &det.fvec);
 347→
 348→	if (cross_mag2 == 0)
 349→		return 0;			//lines are parallel
 350→
 351→	det.uvec = *v2;
 352→	d = calc_det_value(&det);
 353→	if (oflow_check(d, cross_mag2))
 354→		return 0;
 355→	else
 356→		*t1 = fixdiv(d, cross_mag2);
 357→
 358→	det.uvec = *v1;
 359→	d = calc_det_value(&det);
 360→	if (oflow_check(d, cross_mag2))
 361→		return 0;
 362→	else
 363→		*t2 = fixdiv(d, cross_mag2);
 364→
 365→	return 1;		//found point
 366→}
