 374→//this version is for when the start and end positions both poke through
 375→//the plane of a side.  In this case, we must do checks against the edge
 376→//of faces
 377→int special_check_line_to_face(vms_vector * newp, vms_vector * p0, vms_vector * p1, segment * seg, int side, int facenum, int nv, fix rad)
 378→{
 379→	{
 380→	vms_vector move_vec;
 381→	fix edge_t, move_t, edge_t2, move_t2, closest_dist;
 382→	fix edge_len, move_len;
 383→	int vertex_list[6];
 384→	int num_faces, edgenum;
 385→	uint32_t edgemask;
 386→	vms_vector* edge_v0, * edge_v1, edge_vec;
 387→	struct side* s = &seg->sides[side];
 388→	vms_vector closest_point_edge, closest_point_move;
 389→
 390→	if (disable_new_fvi_stuff)
 391→		return check_line_to_face(newp, p0, p1, seg, side, facenum, nv, rad);
 392→
 393→	//calc some basic stuff
 394→
 395→	create_abs_vertex_lists(&num_faces, vertex_list, seg - Segments, side);
 396→	vm_vec_sub(&move_vec, p1, p0);
 397→
 398→	//figure out which edge(s) to check against
 399→
 400→	edgemask = check_point_to_face(p0, seg, s, facenum, nv, vertex_list);
 401→
 402→	if (edgemask == 0)
 403→		return check_line_to_face(newp, p0, p1, seg, side, facenum, nv, rad);
 404→
 405→	for (edgenum = 0; !(edgemask & 1); edgemask >>= 1, edgenum++);
 406→
 407→	edge_v0 = &Vertices[vertex_list[facenum * 3 + edgenum]];
 408→	edge_v1 = &Vertices[vertex_list[facenum * 3 + ((edgenum + 1) % nv)]];
 409→
 410→	vm_vec_sub(&edge_vec, edge_v1, edge_v0);
 411→
 412→	//is the start point already touching the edge?
 413→
 414→	//??
 415→
 416→	//first, find point of closest approach of vec & edge
 417→
 418→	edge_len = vm_vec_normalize(&edge_vec);
 419→	move_len = vm_vec_normalize(&move_vec);
 420→
 421→	check_line_to_line(&edge_t, &move_t, edge_v0, &edge_vec, p0, &move_vec);
 422→
 423→	//make sure t values are in valid range
 424→
 425→	if (move_t<0 || move_t>move_len + rad)
 426→		return IT_NONE;
 427→
 428→	if (move_t > move_len)
 429→		move_t2 = move_len;
 430→	else
 431→		move_t2 = move_t;
 432→
 433→	if (edge_t < 0)		//saturate at points
 434→		edge_t2 = 0;
 435→	else
 436→		edge_t2 = edge_t;
 437→
 438→	if (edge_t2 > edge_len)		//saturate at points
 439→		edge_t2 = edge_len;
 440→
 441→	//now, edge_t & move_t determine closest points.  calculate the points.
 442→
 443→	vm_vec_scale_add(&closest_point_edge, edge_v0, &edge_vec, edge_t2);
 444→	vm_vec_scale_add(&closest_point_move, p0, &move_vec, move_t2);
 445→
 446→	//find dist between closest points
 447→
 448→	closest_dist = vm_vec_dist(&closest_point_edge, &closest_point_move);
 449→
 450→	//could we hit with this dist?
 451→
 452→	//note massive tolerance here
 453→//	if (closest_dist < (rad*18)/20) {		//we hit.  figure out where
 454→	if (closest_dist < (rad * 15) / 20) //we hit.  figure out where
 455→	{
 456→		//now figure out where we hit
 457→
 458→		vm_vec_scale_add(newp, p0, &move_vec, move_t - rad);
 459→
 460→		return IT_EDGE;
 461→	}
 462→	else
 463→		return IT_NONE;			//no hit
 464→	}
 465→}
