 467→//maybe this routine should just return the distance and let the caller
 468→//decide it it's close enough to hit
 469→//determine if and where a vector intersects with a sphere
 470→//vector defined by p0,p1 
 471→//returns dist if intersects, and fills in intp
 472→//else returns 0
 473→int check_vector_to_sphere_1(vms_vector* intp, vms_vector* p0, vms_vector* p1, vms_vector* sphere_pos, fix sphere_rad)
 474→{
 475→	{
 476→	vms_vector d, dn, w, closest_point;
 477→	fix mag_d, dist, w_dist, int_dist;
 478→
 479→	//this routine could be optimized if it's taking too much time!
 480→
 481→	vm_vec_sub(&d, p1, p0);
 482→	vm_vec_sub(&w, sphere_pos, p0);
 483→
 484→	mag_d = vm_vec_copy_normalize(&dn, &d);
 485→
 486→	if (mag_d == 0) 
 487→	{
 488→		int_dist = vm_vec_mag(&w);
 489→		*intp = *p0;
 490→		return (int_dist < sphere_rad) ? int_dist : 0;
 491→	}
 492→
 493→	w_dist = vm_vec_dot(&dn, &w);
 494→
 495→	if (w_dist < 0)		//moving away from object
 496→		return 0;
 497→
 498→	if (w_dist > mag_d + sphere_rad)
 499→		return 0;		//cannot hit
 500→
 501→	vm_vec_scale_add(&closest_point, p0, &dn, w_dist);
 502→
 503→	dist = vm_vec_dist(&closest_point, sphere_pos);
 504→
 505→	if (dist < sphere_rad) 
 506→	{
 507→		fix dist2, rad2, shorten;
 508→
 509→		dist2 = fixmul(dist, dist);
 510→		rad2 = fixmul(sphere_rad, sphere_rad);
 511→
 512→		shorten = fix_sqrt(rad2 - dist2);
 513→
 514→		int_dist = w_dist - shorten;
 515→
 516→		if (int_dist > mag_d || int_dist < 0)
 517→		{
 518→			//past one or the other end of vector, which means we're inside
 519→
 520→			*intp = *p0;		//don't move at all
 521→			return 1;
 522→		}
 523→
 524→		vm_vec_scale_add(intp, p0, &dn, int_dist);         //calc intersection point
 525→
 526→//		{
 527→//			fix dd = vm_vec_dist(intp,sphere_pos);
 528→//			Assert(dd == sphere_rad);
 529→//			mprintf(0,"dd=%x, rad=%x, delta=%x\n",dd,sphere_rad,dd-sphere_rad);
 530→//		}
 531→
 532→
 533→		return int_dist;
 534→	}
 535→	else
 536→		return 0;
 537→	}
 538→}
