 583→//Find out if a vector intersects with anything.
 584→//Fills in hit_data, an fvi_info structure (see header file).
 585→//Parms:
 586→//  p0 & startseg 	describe the start of the vector
 587→//  p1 					the end of the vector
 588→//  rad 					the radius of the cylinder
 589→//  thisobjnum 		used to prevent an object with colliding with itself
 590→//  ingore_obj			ignore collisions with this object
 591→//  check_obj_flag	determines whether collisions with objects are checked
 592→//Returns the hit_data->hit_type
 593→int find_vector_intersection(fvi_query* fq, fvi_info* hit_data)
 594→{
 595→#ifdef USE_OX_BRIDGE
