1136→//finds the uv coords of the given point on the given seg & side
1137→//fills in u & v
1138→void find_hitpoint_uv(fix* u, fix* v, vms_vector* pnt, segment* seg, int sidenum, int facenum)
1139→{
1140→	vms_vector_array* pnt_array;
1141→	vms_vector_array normal_array;
1142→	int segnum = seg - Segments;
1143→	int num_faces;
1144→	int biggest, ii, jj;
1145→	side* side = &seg->sides[sidenum];
1146→	int vertex_list[6], vertnum_list[6];
1147→	vec2d p1, vec0, vec1, checkp;	//@@,checkv;
1148→	uvl uvls[3];
1149→	fix k0, k1;
1150→	int i;
1151→
1152→	//mprintf(0,"\ncheck_trans_wall  vec=%x,%x,%x\n",pnt->x,pnt->y,pnt->z);
1153→
1154→	//do lasers pass through illusory walls?
1155→
1156→	//when do I return 0 & 1 for non-transparent walls?
1157→
1158→	create_abs_vertex_lists(&num_faces, vertex_list, segnum, sidenum);
1159→	create_all_vertnum_lists(&num_faces, vertnum_list, segnum, sidenum);
1160→
1161→	//now the hard work.
1162→
1163→	//1. find what plane to project this wall onto to make it a 2d case
1164→
1165→	memcpy(&normal_array, &side->normals[facenum], sizeof(vms_vector_array));
1166→	biggest = 0;
1167→
1168→	if (abs(normal_array.xyz[1]) > abs(normal_array.xyz[biggest])) biggest = 1;
1169→	if (abs(normal_array.xyz[2]) > abs(normal_array.xyz[biggest])) biggest = 2;
1170→
1171→	if (biggest == 0) ii = 1; else ii = 0;
1172→	if (biggest == 2) jj = 1; else jj = 2;
1173→
1174→	//2. compute u,v of intersection point
1175→
1176→	//vec from 1 -> 0
1177→	pnt_array = (vms_vector_array*)& Vertices[vertex_list[facenum * 3 + 1]];
1178→	p1.i = pnt_array->xyz[ii];
1179→	p1.j = pnt_array->xyz[jj];
1180→
1181→	pnt_array = (vms_vector_array*)& Vertices[vertex_list[facenum * 3 + 0]];
1182→	vec0.i = pnt_array->xyz[ii] - p1.i;
1183→	vec0.j = pnt_array->xyz[jj] - p1.j;
1184→
1185→	//vec from 1 -> 2
1186→	pnt_array = (vms_vector_array*)& Vertices[vertex_list[facenum * 3 + 2]];
1187→	vec1.i = pnt_array->xyz[ii] - p1.i;
1188→	vec1.j = pnt_array->xyz[jj] - p1.j;
1189→
1190→	//vec from 1 -> checkpoint
1191→	pnt_array = (vms_vector_array*)pnt;
1192→	checkp.i = pnt_array->xyz[ii];
1193→	checkp.j = pnt_array->xyz[jj];
1194→
1195→	//@@checkv.i = checkp.i - p1.i;
1196→	//@@checkv.j = checkp.j - p1.j;
1197→
1198→	//mprintf(0," vec0   = %x,%x  ",vec0.i,vec0.j);
1199→	//mprintf(0," vec1   = %x,%x  ",vec1.i,vec1.j);
1200→	//mprintf(0," checkv = %x,%x\n",checkv.i,checkv.j);
1201→
1202→	k1 = -fixdiv(cross(&checkp, &vec0) + cross(&vec0, &p1), cross(&vec0, &vec1));
1203→	if (vec0.i)
1204→		k0 = fixdiv(fixmul(-k1, vec1.i) + checkp.i - p1.i, vec0.i);
1205→	else
1206→		k0 = fixdiv(fixmul(-k1, vec1.j) + checkp.j - p1.j, vec0.j);
1207→
1208→	//mprintf(0," k0,k1  = %x,%x\n",k0,k1);
1209→
1210→	for (i = 0; i < 3; i++)
1211→		uvls[i] = side->uvls[vertnum_list[facenum * 3 + i]];
1212→
1213→	*u = uvls[1].u + fixmul(k0, uvls[0].u - uvls[1].u) + fixmul(k1, uvls[2].u - uvls[1].u);
1214→	*v = uvls[1].v + fixmul(k0, uvls[0].v - uvls[1].v) + fixmul(k1, uvls[2].v - uvls[1].v);
1215→
1216→	//mprintf(0," u,v    = %x,%x\n",*u,*v);
1217→}
