1219→//check if a particular point on a wall is a transparent pixel
1220→//returns 1 if can pass though the wall, else 0
1221→int check_trans_wall(vms_vector* pnt, segment* seg, int sidenum, int facenum)
1222→{
1223→	grs_bitmap* bm;
1224→	side* side = &seg->sides[sidenum];
1225→	int bmx, bmy;
1226→	fix u, v;
1227→
1228→	Assert(WALL_IS_DOORWAY(seg, sidenum) == WID_TRANSPARENT_WALL);
1229→
1230→	find_hitpoint_uv(&u, &v, pnt, seg, sidenum, facenum);
1231→
1232→	if (side->tmap_num2 != 0) 
1233→	{
1234→		bm = texmerge_get_cached_bitmap(side->tmap_num, side->tmap_num2);
1235→	}
1236→	else 
1237→	{
1238→		bm = &GameBitmaps[Textures[side->tmap_num].index];
1239→		PIGGY_PAGE_IN(Textures[side->tmap_num]);
1240→	}
1241→
1242→	if (bm->bm_flags & BM_FLAG_RLE)
1243→		bm = rle_expand_texture(bm);
1244→
1245→	bmx = ((unsigned)f2i(u * bm->bm_w)) % bm->bm_w;
1246→	bmy = ((unsigned)f2i(v * bm->bm_h)) % bm->bm_h;
1247→
1248→	//note: the line above had -v, but that was wrong, so I changed it.  if 
1249→	//something doesn't work, and you want to make it negative again, you 
1250→	//should figure out what's going on.
1251→
1252→		//mprintf(0," bmx,y  = %d,%d, color=%x\n",bmx,bmy,bm->bm_data[bmy*64+bmx]);
1253→
1254→	return (bm->bm_data[bmy * bm->bm_w + bmx] == 255);
1255→}
