368→{
369→	vms_matrix det;
370→	fix d,cross_mag2;		//mag squared cross product
371→
372→	vm_vec_sub(&det.rvec,p2,p1);
373→	vm_vec_cross(&det.fvec,v1,v2);
374→	cross_mag2 = vm_vec_dot(&det.fvec,&det.fvec);
375→
376→	if (cross_mag2 == 0)
377→		return 0;			//lines are parallel
378→
379→	det.uvec = *v2;
380→	d = calc_det_value(&det);
381→	if (oflow_check(d,cross_mag2))
382→		return 0;
383→	else
384→		*t1 = fixdiv(d,cross_mag2);
385→
386→	det.uvec = *v1;
387→	d = calc_det_value(&det);
388→	if (oflow_check(d,cross_mag2))
389→		return 0;
390→	else
391→		*t2 = fixdiv(d,cross_mag2);
392→
393→	return 1;		//found point
394→}
