### **OCaml Implementation (/Users/richard/code/ChocolateDescent/ox/ox_fvi.ml:99-134)**

```ocaml
(* Check if a sphere (center pnt, radius rad) intersects a face.
   Returns IT_FACE, IT_EDGE, IT_POINT, or IT_NONE. *)
let check_sphere_to_face ~pnt ~norm ~nv ~rad ~(vertex_positions : vec3 array) =
  let open Ox_math in
  let edgemask = check_point_to_face ~checkp:pnt ~norm ~nv ~vertex_positions in
  if edgemask = 0
  then it_face
  else (
    (* Find first set bit *)
    let em = ref edgemask in
    let edgenum = ref 0 in
    while !em land 1 = 0 do
      em := !em asr 1;
      incr edgenum
    done;
    let v0 = vertex_positions.(!edgenum) in
    let v1 = vertex_positions.((!edgenum + 1) mod nv) in
    let checkvec = vm_vec_sub ~a:pnt ~b:v0 in
    let edgelen, edgevec = vm_vec_normalized_dir ~v_end:v1 ~v_start:v0 in
    let d = vm_vec_dotprod ~a:edgevec ~b:checkvec in
    if wrap32 (d + rad) < 0
    then it_none
    else if wrap32 (d - rad) > edgelen
    then it_none
    else (
      let itype = ref it_point in
      let closest_point =
        if d < 0
        then v0
        else if d > edgelen
        then v1
        else (
          itype := it_edge;
          vm_vec_scale_add ~a:v0 ~b:edgevec ~k:d)
      in
      let dist = vm_vec_dist ~a:pnt ~b:closest_point in
      if dist <= rad then if !itype = it_point then it_none else !itype else it_none))
```

**Key Differences:**
- **C signature**: takes `segment* sp` and `side* s` parameters (not used directly)
- **OCaml signature**: takes `norm` (face normal) and `vertex_positions` array directly
- **C**: finds edge bit with loop-and-shift pattern
- **OCaml**: same logic but uses ref with `land` and `asr` operators  
- **Both**: use `wrap32()` in OCaml vs implicit C wrapping on comparisons (lines 117-119)
- **Line 117-119 concern**: OCaml uses `wrap32()` on intermediate calculations `(d + rad)` and `(d - rad)`, but C does NOT explicitly wrap these before comparison—this could be a divergence if overflow happens

