## 1. check_vector_to_sphere_1 - Ray-Sphere Intersection

### **C Implementation (D1: /Users/richard/code/ChocolateDescent/main_d1/fvi.cpp:473-538)**

```c
int check_vector_to_sphere_1(vms_vector* intp, vms_vector* p0, vms_vector* p1, 
                             vms_vector* sphere_pos, fix sphere_rad)
{
	vms_vector d, dn, w, closest_point;
	fix mag_d, dist, w_dist, int_dist;

	vm_vec_sub(&d, p1, p0);
	vm_vec_sub(&w, sphere_pos, p0);

	mag_d = vm_vec_copy_normalize(&dn, &d);

	if (mag_d == 0) 
	{
		int_dist = vm_vec_mag(&w);
		*intp = *p0;
		return (int_dist < sphere_rad) ? int_dist : 0;
	}

	w_dist = vm_vec_dot(&dn, &w);

	if (w_dist < 0)		//moving away from object
		return 0;

	if (w_dist > mag_d + sphere_rad)
		return 0;		//cannot hit

	vm_vec_scale_add(&closest_point, p0, &dn, w_dist);

	dist = vm_vec_dist(&closest_point, sphere_pos);

	if (dist < sphere_rad) 
	{
		fix dist2, rad2, shorten;

		dist2 = fixmul(dist, dist);
		rad2 = fixmul(sphere_rad, sphere_rad);

		shorten = fix_sqrt(rad2 - dist2);

		int_dist = w_dist - shorten;

		if (int_dist > mag_d || int_dist < 0)
		{
			//past one or the other end of vector, which means we're inside

			*intp = *p0;		//don't move at all
			return 1;
		}

		vm_vec_scale_add(intp, p0, &dn, int_dist);  //calc intersection point

		return int_dist;
	}
	else
		return 0;
}
```

### **OCaml Implementation (/Users/richard/code/ChocolateDescent/ox/ox_fvi.ml:286-314)**

```ocaml
(* Ray-sphere intersection. Returns (dist, intp) where dist=0 means no hit. *)
let check_vector_to_sphere_1 ~p0 ~p1 ~sphere_pos ~sphere_rad =
  let open Ox_math in
  let d = vm_vec_sub ~a:p1 ~b:p0 in
  let w = vm_vec_sub ~a:sphere_pos ~b:p0 in
  let mag_d, dn = vm_vec_copy_normalize ~v:d in
  if mag_d = 0
  then (
    let int_dist = vm_vec_mag ~v:w in
    if int_dist < sphere_rad then int_dist, p0 else 0, p0)
  else (
    let w_dist = vm_vec_dotprod ~a:dn ~b:w in
    if w_dist < 0
    then 0, (0, 0, 0) (* moving away *)
    else if w_dist > wrap32 (mag_d + sphere_rad)
    then 0, (0, 0, 0) (* cannot hit *)
    else (
      let closest_point = vm_vec_scale_add ~a:p0 ~b:dn ~k:w_dist in
      let dist = vm_vec_dist ~a:closest_point ~b:sphere_pos in
      if dist < sphere_rad
      then (
        let dist2 = fixmul ~a:dist ~b:dist in
        let rad2 = fixmul ~a:sphere_rad ~b:sphere_rad in
        let shorten = fix_sqrt ~a:(wrap32 (rad2 - dist2)) in
        let int_dist = wrap32 (w_dist - shorten) in
        if int_dist > mag_d || int_dist < 0
        then 1, p0 (* inside sphere *)
        else (
          let intp = vm_vec_scale_add ~a:p0 ~b:dn ~k:int_dist in
          int_dist, intp))
      else 0, (0, 0, 0)))
```

**Key Differences:**
- **C returns**: single fix value (distance), modifies `intp` pointer
- **OCaml returns**: tuple of (distance, intp_vector)
- **Both identical logic**, but C uses 32-bit operations implicitly; OCaml uses `wrap32()` on line 299, 308, 309 for explicit wrapping during arithmetic
- **Line 308**: OCaml explicitly wraps `(rad2 - dist2)` which could be negative before fix_sqrt

