262→static int compare_ai_local(const ai_local *aa, const ai_local *ab, int idx)
263→{
264→	int divergences = 0;
265→	int a_val, b_val;
266→	char prefix[64];
267→	snprintf(prefix, sizeof(prefix), "Ai_local[%d]", idx);
268→
269→	CMP_FIELD(prefix, player_awareness_type, aa->player_awareness_type, ab->player_awareness_type);
270→	CMP_FIELD(prefix, retry_count, aa->retry_count, ab->retry_count);
271→	CMP_FIELD(prefix, consecutive_retries, aa->consecutive_retries, ab->consecutive_retries);
272→	CMP_FIELD(prefix, mode, aa->mode, ab->mode);
