 35→/* Ring buffer for frame records - flush when full */
 36→#define RECORD_BUFFER_SIZE 1024
 37→
 38→static FILE *record_file = NULL;
 39→static int recording_active = 0;
 40→static uint32_t total_frames_recorded = 0;
 41→static long header_offset = 0;  /* file offset of header for patching num_frames */
 42→
 43→static ox_frame_record record_buffer[RECORD_BUFFER_SIZE];
 44→static int buffer_count = 0;
 45→static ox_replay_header saved_header;
 46→
 47→/* Forward declaration for atexit handler */
 48→void ox_recorder_close(void);
 49→
 50→static void atexit_flush(void)
 51→{
 52→	if (recording_active)
 53→		ox_recorder_close();
 54→}
 55→
 56→static void flush_buffer(void)
 57→{
 58→	if (buffer_count > 0 && record_file) {
 59→		fwrite(record_buffer, sizeof(ox_frame_record), buffer_count, record_file);
 60→		fflush(record_file);
 61→		buffer_count = 0;
 62→	}
 63→}
 64→
 65→int ox_recorder_init(const char *filename)
 66→{
 67→	record_file = fopen(filename, "wb");
 68→	if (!record_file) {
 69→		fprintf(stderr, "OX_REPLAY: failed to open '%s' for recording\n", filename);
 70→		return -1;
 71→	}
 72→
 73→	/* Write placeholder header - will be patched on close */
 74→	ox_replay_header hdr;
 75→	memset(&hdr, 0, sizeof(hdr));
 76→	hdr.magic = OX_REPLAY_MAGIC;
 77→	hdr.version = OX_REPLAY_VERSION;
 78→	header_offset = 0;
 79→	fwrite(&hdr, sizeof(hdr), 1, record_file);
 80→	fflush(record_file);
 81→
 82→	recording_active = 1;
 83→	total_frames_recorded = 0;
 84→	buffer_count = 0;
 85→
 86→	atexit(atexit_flush);
 87→
 88→	fprintf(stderr, "OX_REPLAY: recording to '%s'\n", filename);
 89→	return 0;
 90→}
 91→
 92→void ox_recorder_level_start(int level_num, int difficulty_level)
 93→{
 94→	if (!recording_active || !record_file)
 95→		return;
 96→
 97→	/* Rewrite header with level info */
 98→	ox_replay_header hdr;
 99→	hdr.magic = OX_REPLAY_MAGIC;
100→	hdr.version = OX_REPLAY_VERSION;
101→	hdr.level_num = level_num;
102→	hdr.difficulty_level = difficulty_level;
103→	hdr.initial_rand_state = P_Rand_get_state();
104→	hdr.highest_object_index = Highest_object_index;
105→	hdr.num_frames = 0;  /* patched on close */
106→
107→	/* Calculate snapshot size: Objects + Ai_local_info + Players + Walls */
108→	int n_obj = Highest_object_index + 1;
109→	if (n_obj > MAX_OBJECTS) n_obj = MAX_OBJECTS;
110→	uint32_t snap_size = n_obj * sizeof(object)
111→	                   + n_obj * sizeof(ai_local)
112→	                   + MAX_PLAYERS * sizeof(player)
113→	                   + Num_walls * sizeof(wall);
114→	hdr.snapshot_size = snap_size;
115→
116→	/* Save header for patching on close */
117→	saved_header = hdr;
118→
119→	/* Seek back to header and rewrite */
120→	fseek(record_file, header_offset, SEEK_SET);
121→	fwrite(&hdr, sizeof(hdr), 1, record_file);
122→
123→	/* Write initial state snapshot */
124→	if (n_obj > 0) {
125→		fwrite(Objects, sizeof(object), n_obj, record_file);
126→		fwrite(Ai_local_info, sizeof(ai_local), n_obj, record_file);
127→	}
128→	fwrite(Players, sizeof(player), MAX_PLAYERS, record_file);
129→	if (Num_walls > 0)
130→		fwrite(Walls, sizeof(wall), Num_walls, record_file);
131→	fflush(record_file);
132→
133→	fprintf(stderr, "OX_REPLAY: level %d start recorded (snapshot %u bytes, %d objects, %d walls)\n",
134→		level_num, snap_size, n_obj, Num_walls);
135→}
