 33→static FILE *replay_file = NULL;
 34→static FILE *state_log = NULL;
 35→static int replaying_active = 0;
 36→
 37→static ox_replay_header replay_header;
 38→static uint32_t frames_replayed = 0;
 39→
 40→/* Initial state snapshot buffer (dynamically allocated based on snapshot_size) */
 41→static uint8_t *initial_snapshot = NULL;
 42→static uint32_t initial_snapshot_size = 0;
 43→
 44→/* Read buffer for frame records */
 45→#define REPLAY_BUFFER_SIZE 1024
 46→static ox_frame_record replay_buffer[REPLAY_BUFFER_SIZE];
 47→static int buffer_pos = 0;
 48→static int buffer_count = 0;
 49→
 50→static int refill_buffer(void)
 51→{
 52→	if (!replay_file)
 53→		return 0;
 54→
 55→	uint32_t remaining = replay_header.num_frames - frames_replayed;
 56→	uint32_t to_read = remaining < REPLAY_BUFFER_SIZE ? remaining : REPLAY_BUFFER_SIZE;
 57→	if (to_read == 0)
 58→		return 0;
 59→
 60→	buffer_count = (int)fread(replay_buffer, sizeof(ox_frame_record), to_read, replay_file);
 61→	buffer_pos = 0;
 62→	return buffer_count;
 63→}
 64→
 65→int ox_replayer_init(const char *replay_filename, const char *state_log_filename)
 66→{
 67→	replay_file = fopen(replay_filename, "rb");
 68→	if (!replay_file) {
 69→		fprintf(stderr, "OX_REPLAY: failed to open '%s' for replay\n", replay_filename);
 70→		return -1;
 71→	}
 72→
 73→	/* Read and validate header */
 74→	if (fread(&replay_header, sizeof(replay_header), 1, replay_file) != 1) {
 75→		fprintf(stderr, "OX_REPLAY: failed to read header from '%s'\n", replay_filename);
 76→		fclose(replay_file);
 77→		replay_file = NULL;
 78→		return -1;
 79→	}
 80→
 81→	if (replay_header.magic != OX_REPLAY_MAGIC) {
 82→		fprintf(stderr, "OX_REPLAY: invalid magic in '%s' (expected 0x%X, got 0x%X)\n",
 83→			replay_filename, OX_REPLAY_MAGIC, replay_header.magic);
 84→		fclose(replay_file);
 85→		replay_file = NULL;
 86→		return -1;
 87→	}
 88→
 89→	if (replay_header.version != OX_REPLAY_VERSION) {
 90→		fprintf(stderr, "OX_REPLAY: version mismatch in '%s' (expected %d, got %d)\n",
 91→			replay_filename, OX_REPLAY_VERSION, replay_header.version);
 92→		fclose(replay_file);
 93→		replay_file = NULL;
 94→		return -1;
 95→	}
 96→
 97→	/* Read initial state snapshot */
 98→	initial_snapshot_size = replay_header.snapshot_size;
 99→	if (initial_snapshot_size > 0) {
100→		initial_snapshot = (uint8_t *)malloc(initial_snapshot_size);
101→		if (!initial_snapshot) {
102→			fprintf(stderr, "OX_REPLAY: failed to allocate %u bytes for snapshot\n",
103→				initial_snapshot_size);
104→			fclose(replay_file);
105→			replay_file = NULL;
106→			return -1;
107→		}
108→		if (fread(initial_snapshot, 1, initial_snapshot_size, replay_file) != initial_snapshot_size) {
109→			fprintf(stderr, "OX_REPLAY: failed to read snapshot from '%s'\n", replay_filename);
110→			free(initial_snapshot);
111→			initial_snapshot = NULL;
112→			fclose(replay_file);
113→			replay_file = NULL;
114→			return -1;
115→		}
116→	}
117→
118→	/* Open state log if requested */
119→	if (state_log_filename && state_log_filename[0]) {
120→		state_log = fopen(state_log_filename, "wb");
121→		if (!state_log) {
122→			fprintf(stderr, "OX_REPLAY: warning: failed to open state log '%s'\n",
123→				state_log_filename);
124→		}
125→	}
126→
127→	replaying_active = 1;
128→	frames_replayed = 0;
129→	buffer_pos = 0;
130→	buffer_count = 0;
131→
132→	fprintf(stderr, "OX_REPLAY: replaying '%s' (level %d, difficulty %d, %u frames)\n",
133→		replay_filename, replay_header.level_num,
134→		replay_header.difficulty_level, replay_header.num_frames);
135→
136→	return 0;
137→}
