149→void ox_replayer_restore_initial_state(void)
150→{
151→	if (!initial_snapshot || initial_snapshot_size == 0)
152→		return;
153→
154→	const uint8_t *p = initial_snapshot;
155→	uint32_t remaining = initial_snapshot_size;
156→
157→	int n_obj = replay_header.highest_object_index + 1;
158→	if (n_obj > MAX_OBJECTS) n_obj = MAX_OBJECTS;
159→
160→	/* Restore Objects */
161→	uint32_t obj_size = n_obj * sizeof(object);
162→	if (remaining >= obj_size) {
163→		memcpy(Objects, p, obj_size);
164→		p += obj_size;
165→		remaining -= obj_size;
166→	}
167→
168→	/* Restore Ai_local_info */
169→	uint32_t ai_size = n_obj * sizeof(ai_local);
170→	if (remaining >= ai_size) {
171→		memcpy(Ai_local_info, p, ai_size);
172→		p += ai_size;
173→		remaining -= ai_size;
174→	}
175→
176→	/* Restore Players */
177→	uint32_t player_size = MAX_PLAYERS * sizeof(player);
178→	if (remaining >= player_size) {
179→		memcpy(Players, p, player_size);
180→		p += player_size;
181→		remaining -= player_size;
182→	}
183→
184→	/* Restore Walls */
185→	if (remaining > 0) {
186→		uint32_t wall_count = remaining / sizeof(wall);
187→		if (wall_count > MAX_WALLS) wall_count = MAX_WALLS;
188→		memcpy(Walls, p, wall_count * sizeof(wall));
189→		Num_walls = wall_count;
190→	}
191→
192→	Highest_object_index = replay_header.highest_object_index;
193→	P_Rand_set_state(replay_header.initial_rand_state);
194→
195→	fprintf(stderr, "OX_REPLAY: initial state restored (%d objects)\n", n_obj);
196→}
